 66	export const SilencedAlertsTable: React.FC<SilencedAlertsTableProps> = ({
 67	  alerts,
 68	  loaded,
 69	  error,
 70	  alertManagerBasePath,
 71	  onRefresh,
 72	}) => {
 73	  const { t } = useCustomTranslation();
 74	  const [selectedAlerts, setSelectedAlerts] = React.useState<
 75	    SilencedAlertRowData[]
 76	  >([]);
 77	  const [nameFilter, setNameFilter] = React.useState('');
 78	  const [severityFilter, setSeverityFilter] = React.useState('all');
 79	  const [isSeverityOpen, setIsSeverityOpen] = React.useState(false);
 80	  const [isUnsilencing, setIsUnsilencing] = React.useState(false);
 81	  const [actionError, setActionError] = React.useState<any>();
 82	
 83	  const severityOptions = React.useMemo(
 84	    () => [
 85	      { value: 'all', label: t('All checks') },
 86	      { value: 'critical', label: t('Critical') },
 87	      { value: 'moderate', label: t('Moderate') },
 88	      { value: 'minor', label: t('Minor') },
 89	    ],
 90	    [t]
 91	  );
 92	
 93	  const filteredAlerts = React.useMemo(
 94	    () =>
 95	      alerts.filter((alert) => {
 96	        // Filter by severity using the SEVERITY_MAP
 97	        let severityMatch = true;
 98	        if (severityFilter !== 'all') {
 99	          const targetSeverity = SEVERITY_MAP[severityFilter];
100	          if (targetSeverity) {
101	            severityMatch =
102	              alert.severity.toLowerCase() === targetSeverity.toLowerCase();
103	          }
104	        }
105	
106	        const nameMatch =
107	          !nameFilter.trim() ||
108	          fuzzyCaseInsensitive(nameFilter, alert.alertname) ||
109	          fuzzyCaseInsensitive(nameFilter, alert.details);
110	        return severityMatch && nameMatch;
111	      }),
112	    [alerts, severityFilter, nameFilter]
113	  );
114	
115	  const onSeveritySelect = React.useCallback((_event, selection: string) => {
116	    setSeverityFilter(selection);
117	    setIsSeverityOpen(false);
118	  }, []);
119	
120	  const onUnsilence = async () => {
121	    if (!alertManagerBasePath) {
122	      return;
123	    }
124	    setIsUnsilencing(true);
125	    setActionError(undefined);
126	    try {
127	      await Promise.all(
128	        selectedAlerts.map((alert) =>
129	          consoleFetch(
130	            getAlertManagerSilenceEndpoint(
131	              alertManagerBasePath,
132	              alert.silenceId
133	            ),
134	            {
135	              method: 'DELETE',
136	            }
137	          ).then((response) => {
138	            if (!response?.ok) {
139	              throw new Error(
140	                `${response.status} ${response.statusText || t('Unknown error')}`
141	              );
142	            }
143	          })
144	        )
145	      );
146	      setSelectedAlerts([]);
147	    } catch (err) {
148	      setActionError(err);
149	    } finally {
150	      onRefresh();
151	      setIsUnsilencing(false);
152	    }
153	  };
154	
155	  const columns = React.useMemo<TableColumnProps[]>(
156	    () => [
157	      {
158	        columnName: t('Silenced on'),
159	        sortFunction: (a, b, direction) => {
160	          const aTime = (a as SilencedAlertRowData).silencedOn?.getTime() || 0;
161	          const bTime = (b as SilencedAlertRowData).silencedOn?.getTime() || 0;
162	          return direction === 'asc' ? bTime - aTime : aTime - bTime;
163	        },
164	      },
165	      {
166	        columnName: t('Check'),
167	        sortFunction: (a, b, direction) => {
168	          const cmp = (a as SilencedAlertRowData).alertname.localeCompare(
169	            (b as SilencedAlertRowData).alertname
170	          );
171	          return direction === 'asc' ? cmp : -cmp;
172	        },
173	      },
174	      {
175	        columnName: t('Details'),
176	      },
177	    ],
178	    [t]
179	  );
180	
181	  const isUnsilenceDisabled =
182	    !selectedAlerts.length || !alertManagerBasePath || isUnsilencing;
183	
184	  const renderSeverityToggle = React.useCallback(
185	    (toggleRef: React.Ref<MenuToggleElement>) => (
186	      <MenuToggle
187	        ref={toggleRef}
188	        onClick={() => setIsSeverityOpen((prev) => !prev)}
189	        isExpanded={isSeverityOpen}
190	      >
191	        {severityOptions.find((opt) => opt.value === severityFilter)?.label ||
192	          t('All checks')}
193	      </MenuToggle>
194	    ),
195	    [severityFilter, isSeverityOpen, severityOptions, t]
196	  );
197	
198	  return (
199	    <>
200	      <Toolbar>
201	        <ToolbarContent>
202	          <ToolbarItem>
203	            <Select
204	              aria-label={t('Filter by severity')}
205	              isOpen={isSeverityOpen}
206	              toggle={renderSeverityToggle}
207	              onOpenChange={setIsSeverityOpen}
208	              onSelect={onSeveritySelect}
209	              selected={severityFilter}
210	              shouldFocusFirstItemOnOpen
211	              shouldFocusToggleOnSelect
212	            >
213	              <SelectList>
214	                {severityOptions.map((option) => (
215	                  <SelectOption key={option.value} value={option.value}>
216	                    {option.label}
217	                  </SelectOption>
218	                ))}
219	              </SelectList>
220	            </Select>
221	          </ToolbarItem>
222	          <ToolbarItem>
223	            <SearchInput
224	              aria-label={t('Find by name')}
225	              placeholder={t('Find by name')}
226	              value={nameFilter}
227	              onChange={(_event, value) => setNameFilter(value)}
228	              onClear={() => setNameFilter('')}
229	            />
230	          </ToolbarItem>
231	          <ToolbarItem>
232	            <Button
233	              variant={ButtonVariant.primary}
234	              onClick={onUnsilence}
235	              isDisabled={isUnsilenceDisabled}
236	              isLoading={isUnsilencing}
237	            >
238	              {t('Unsilence')}
239	            </Button>
240	          </ToolbarItem>
241	        </ToolbarContent>
242	      </Toolbar>
243	      {actionError && (
244	        <Alert
245	          isInline
246	          variant={AlertVariant.danger}
247	          title={t('Unable to unsilence the selected alerts')}
248	          className="pf-v6-u-mb-md"
249	        >
250	          {actionError?.message}
251	        </Alert>
252	      )}
253	      <SelectableTable
254	        rows={filteredAlerts}
255	        columns={columns}
256	        RowComponent={RowRenderer}
257	        selectedRows={selectedAlerts}
258	        setSelectedRows={setSelectedAlerts}
259	        loaded={loaded}
260	        loadError={error}
261	        initialSortColumnIndex={0}
262	        borders={true}
263	        variant={TableVariant.DEFAULT}
264	      />
265	    </>
266	  );
267	};
